mapper.select:
select

FROM AGG_HOST_CPU_MEM_DETAIL_5M


        and TIME >= #{startTime}


        and TIME <= #{endTime}


GROUP BY TIME, HOST_POOL_ID, CLUSTER_ID, HOST_ID, OP_GROUP_ID, OP_GROUP_CODE

    order by #{sortField}


    #{sortDir}

SELECT FLOW.HOST_ID as hostId, TD.name as name,


        round(avgMerge(FLOW.CPU_RATE_AVG),2)  as cpuRateAvg


        round(avgMerge(FLOW.MEMORY_RATE_AVG),2)  as memoryRateAvg


FROM AGG_HOST_CPU_MEM_DETAIL_5M FLOW, ${@com.h3c.h3cloud.performance.monitor.service.mapper.base.clickhouseMapperConstant@TBL_HOST} TD  WHERE TD.id = FLOW.HOST_ID
AND TIME BETWEEN ${startTime} AND ${endTime}

    AND FLOW.HOST_POOL_ID  =${hostPoolId}


    AND FLOW.CLUSTER_ID =${clusterId}


    AND TD.op_group_code LIKE #{operatorGroupCode}

GROUP BY FLOW.HOST_ID, TD.name


        ORDER BY cpuRateAvg DESC


        ORDER BY memoryRateAvg DESC



    LIMIT ${limit}
